    sources: [{"id": "wetwijzer-bedrijven", "title": "WetWijzer Bedrijven (KOOP/Logius)", "categorie": "Open-source RAG-referentie", "omschrijving": "Nederlands referentievoorbeeld voor RAG bij de overheid; volledig open-source gerealiseerd. Eindrapport en broncode beschikbaar op GitLab.\n", "url": "https://gitlab.com/koop/innovatielab/wetwijzer-bedrijven-prototype"}, {"id": "dense-sparse-retrieval", "title": "Dense vs. Sparse Retrieval (FAISS, BM25, Hybrid Search)", "categorie": "Richtlijnen", "omschrijving": "Achtergrondartikel over de werking van hybride zoekstrategieën in RAG-toepassingen.\n", "url": "https://dev.to/qvfagundes/dense-vs-sparse-retrieval-mastering-faiss-bm25-and-hybrid-search-4kb1"}, {"id": "nvidia-chunking-strategy", "title": "NVIDIA — Finding the Best Chunking Strategy", "categorie": "Richtlijnen", "omschrijving": "Benchmark van chunkingstrategieën voor RAG-pijplijnen op gemengde datasets.\n", "url": "https://developer.nvidia.com/blog/finding-the-best-chunking-strategy-for-accurate-ai-responses/"}, {"id": "e5-nl-embeddings", "title": "E5-NL embedding-modellen", "categorie": "Tools", "omschrijving": "Open-source Nederlandse embedding-modellen, beschikbaar op Hugging Face.\n", "url": "https://huggingface.co/models?search=e5-nl"}, {"id": "qdrant", "title": "Qdrant", "categorie": "Tools", "omschrijving": "Open-source self-hostable vectordatabase, populair bij productie-RAG.\n", "url": "https://qdrant.tech/"}, {"id": "milvus", "title": "Milvus", "categorie": "Tools", "omschrijving": "Open-source vectordatabase die ook door NVIDIA Blueprint en VLAM.AI-omgevingen wordt gebruikt.\n", "url": "https://milvus.io/"}, {"id": "weaviate", "title": "Weaviate", "categorie": "Tools", "omschrijving": "Open-source vectordatabase met hybrid-search-functionaliteit ingebakken.\n", "url": "https://weaviate.io/"}],
